import "./styles/History.css";

function HistoryByCategory() {
  const history = [
    { category: "Fantasy", count: 5 },
    { category: "Business", count: 2 },
    { category: "Technology", count: 4 },
    { category: "Literature", count: 3 },
  ];

  return (
    <div className="history-page">
      <h1 className="history-title">Borrowing History</h1>

      <div className="history-list">
        {history.map((item, index) => (
          <div key={index} className="history-card">
            <span className="history-category">{item.category}</span>
            <span className="history-count">{item.count} books</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default HistoryByCategory;
